function Card({children,style:s={}}){return<div style={{background:C.bg2,border:`1px solid ${C.bd}`,borderRadius:R.l,padding:20,overflow:"hidden",...s}}>{children}</div>}
function Dot({s}){return<span style={{width:7,height:7,borderRadius:"50%",background:{active:C.grn,paused:C.amb,killed:C.red,connected:C.grn}[s]||C.g1,display:"inline-block",flexShrink:0}}/>}
function Sev({s}){const m={critical:{c:C.red,l:"CRITICAL"},warning:{c:C.amb,l:"WARNING"},info:{c:C.blu,l:"INFO"},high:{c:C.red,l:"HIGH"},medium:{c:C.amb,l:"MEDIUM"},low:{c:C.grn,l:"LOW"},significant:{c:C.amb,l:"SIGNIF"},none:{c:C.g2,l:"NONE"}};const v=m[s]||m.info;return<span style={{fontFamily:F.m,fontSize:9,fontWeight:700,padding:"3px 8px",borderRadius:4,background:`${v.c}12`,border:`1px solid ${v.c}30`,color:v.c}}>{v.l}</span>}
function Btn({children,v="def",sz="sm",style:s={},...p}){const vs={def:{background:C.bg3,color:C.g3,border:`1px solid ${C.bd}`},pri:{background:`linear-gradient(135deg,${C.gold},${C.gold2})`,color:C.bg1,border:"none"},dan:{background:C.redD,color:C.red,border:`1px solid ${C.redB}`},suc:{background:C.grnD,color:C.grn,border:`1px solid ${C.grnB}`},gh:{background:"transparent",color:C.g3,border:"none"}};return<button style={{borderRadius:R.m,fontWeight:600,display:"inline-flex",alignItems:"center",gap:6,cursor:"pointer",padding:"6px 12px",fontSize:12,...(vs[v]||vs.def),...s}} {...p}>{children}</button>}
function Stat({label,value,sub,color=C.gold,info}){return<Card><div style={{display:"flex",alignItems:"center",marginBottom:10}}><span style={{fontFamily:F.m,fontSize:9,color:C.g2,letterSpacing:".1em",textTransform:"uppercase"}}>{label}</span>{info&&<Tip t={info}/>}</div><div style={{display:"flex",alignItems:"baseline",gap:6}}><span style={{fontFamily:F.h,fontSize:28,fontWeight:800,color}}>{value}</span>{sub&&<span style={{fontSize:12,color:C.g2}}>{sub}</span>}</div></Card>}
function Tip({t}){const[show,setShow]=useState(false);return<span style={{position:"relative",display:"inline-flex",marginLeft:4}} onMouseEnter={()=>setShow(true)} onMouseLeave={()=>setShow(false)}><span style={{width:14,height:14,borderRadius:"50%",background:C.bg3,border:`1px solid ${C.bd}`,display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:9,color:C.g2,cursor:"help",fontWeight:700}}>?</span>{show&&<div style={{position:"absolute",bottom:"calc(100% + 6px)",left:0,background:"#1a2540",border:`1px solid ${C.goldB}`,borderRadius:R.s,padding:"8px 12px",fontSize:11,color:C.g4,width:220,zIndex:200,lineHeight:1.5,boxShadow:"0 4px 24px rgba(0,0,0,.6)"}}>{t}</div>}</span>}
function Bar({data,h=40,color=C.gold}){const[hov,setHov]=useState(null);if(!data||!data.length)return null;const mx=Math.max(...data),mn=Math.min(...data),rng=mx-mn||1;return<div style={{display:"flex",alignItems:"flex-end",gap:3,height:h}}>{data.map((v,i)=>{const ht=((v-mn)/rng)*100;return<div key={i} style={{flex:1,height:`${Math.max(8,ht)}%`,position:"relative"}} onMouseEnter={()=>setHov(i)} onMouseLeave={()=>setHov(null)}><div style={{width:"100%",height:"100%",borderRadius:"2px 2px 0 0",background:color,opacity:hov===i?1:.3+(i/data.length)*.7,cursor:"crosshair"}}/>{hov===i&&<div style={{position:"absolute",bottom:"calc(100% + 4px)",left:"50%",transform:"translateX(-50%)",background:C.bg3,border:`1px solid ${C.goldB}`,borderRadius:4,padding:"4px 8px",fontSize:10,fontFamily:F.m,color:C.w,whiteSpace:"nowrap",zIndex:50}}>{v}</div>}</div>})}</div>}
function Line({data,h=80,color=C.gold}){const[hov,setHov]=useState(null);if(!data||data.length<2)return null;const vals=data.map(d=>typeof d==="number"?d:d.score||0);const mx=Math.max(...vals),mn=Math.min(...vals),rng=mx-mn||1;const pts=vals.map((v,i)=>({x:4+(i/(vals.length-1))*392,y:4+(h-8)-((v-mn)/rng)*(h-8),v}));const path=pts.map((p,i)=>`${i===0?"M":"L"} ${p.x} ${p.y}`).join(" ");return<svg viewBox={`0 0 400 ${h}`} style={{width:"100%",height:"auto"}}><path d={`${path} L ${pts[pts.length-1].x} ${h-4} L 4 ${h-4} Z`} fill={color} opacity=".06"/><path d={path} fill="none" stroke={color} strokeWidth="2" strokeLinecap="round"/>{pts.map((p,i)=><g key={i} onMouseEnter={()=>setHov(i)} onMouseLeave={()=>setHov(null)} style={{cursor:"crosshair"}}><rect x={p.x-8} y={0} width={16} height={h} fill="transparent"/>{hov===i&&<circle cx={p.x} cy={p.y} r={4} fill={color}/>}{hov===i&&<g><rect x={p.x-18} y={p.y-18} width={36} height={14} rx={3} fill={C.bg3} stroke={color} strokeWidth=".5"/><text x={p.x} y={p.y-8} textAnchor="middle" fontSize="9" fontFamily={F.m} fill={C.w}>{p.v}</text></g>}</g>)}</svg>}
function Tbl({cols,data,onRow}){return<div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse"}}><thead><tr>{cols.map(c=><th key={c.k} style={{textAlign:"left",padding:"10px 12px",fontFamily:F.m,fontSize:9,color:C.g2,letterSpacing:".1em",textTransform:"uppercase",borderBottom:`1px solid ${C.bd}`}}>{c.l}</th>)}</tr></thead><tbody>{data.map((r,i)=><tr key={r.id||i} onClick={()=>onRow&&onRow(r)} style={{cursor:onRow?"pointer":"default"}} onMouseEnter={e=>e.currentTarget.style.background=C.bg3} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>{cols.map(c=><td key={c.k} style={{padding:"10px 12px",fontSize:13,color:C.g3,borderBottom:`1px solid ${C.bd}`,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:200}}>{c.r?c.r(r[c.k],r):r[c.k]}</td>)}</tr>)}{!data.length&&<tr><td colSpan={cols.length} style={{padding:32,textAlign:"center",color:C.g2}}>No data</td></tr>}</tbody></table></div>}

